VALUES
  ('dietitian-moex-00223', 'dietitian', 'dietitian-moex-114-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '林先生35歲，身高175公分體重60公斤，因車禍嚴重創傷住進ICU併發急性腎損傷（acute kidney injury），使用CVVHD治療期間，他的每日蛋白質需要量為何？', '["1.5～2.5 g/kg", "1.0～1.2 g/kg", "0.8～1.0 g/kg", "0.4～0.6 g/kg"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:49+00:00", "source_pdf_sha1": "7aa83b1fecb3", "answer_pdf_sha1": "65efadb3135a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "102", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00224', 'dietitian', 'dietitian-moex-114-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '小明是國小三年級生，因先天泌尿道異常導致慢性腎臟病。有關他的飲食治療，下列何者錯誤？', '["為維持正常生長，需降低飲食蛋白質攝取量", "熱量需要量與一般同年齡兒童相同", "鈣質攝取不足時可以服用碳酸鈣補充", "血磷過高時可以使用碳酸鈣降低磷的吸收"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:49+00:00", "source_pdf_sha1": "7aa83b1fecb3", "answer_pdf_sha1": "65efadb3135a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "102", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00225', 'dietitian', 'dietitian-moex-114-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '林先生3個月前進行腎臟移植，下列何者不是他會出現的異常？', '["高血糖", "高血脂", "高血磷", "高血鉀"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:49+00:00", "source_pdf_sha1": "7aa83b1fecb3", "answer_pdf_sha1": "65efadb3135a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "102", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00226', 'dietitian', 'dietitian-moex-114-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '宋先生為末期腎臟病病人（ESRD）需要進行透析治療，他想瞭解血液透析與腹膜透析的差異，下列 何者正確？', '["腹膜透析清除的鉀較少", "腹膜透析每小時清除的代謝廢物較多", "腹膜透析每次脫水量較多", "腹膜透析流失的蛋白質較多"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:49+00:00", "source_pdf_sha1": "7aa83b1fecb3", "answer_pdf_sha1": "65efadb3135a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "102", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00227', 'dietitian', 'dietitian-moex-114-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關Mediterranean diet的原則，下列何者最不適當？', '["減少以紅肉作為蛋白質來源", "蛋白質來源可多選擇全脂乳製品與瘦肉", "強調多選擇根莖類與綠色蔬菜", "烹調用油以芥花油取代玉米油"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:49+00:00", "source_pdf_sha1": "7aa83b1fecb3", "answer_pdf_sha1": "65efadb3135a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "102", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00228', 'dietitian', 'dietitian-moex-114-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '得舒飲食（DASH diet）能充分提供多種有助於維持或改善血壓的營養素，但較未強調以下何項營 養素的食物攝取？', '["鎂", "鈣", "鉀", "鋅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:49+00:00", "source_pdf_sha1": "7aa83b1fecb3", "answer_pdf_sha1": "65efadb3135a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "102", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00229', 'dietitian', 'dietitian-moex-114-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關心臟衰竭（heart failure）的病理變化，下列何者正確？', '["由心室分泌的B-natriuretic peptide（BNP）濃度會顯著下降", "因體液滯留導致器官灌流不足（hypoperfusion），前臂和腿部溫度較低", "病程惡化時，病人坐著休息也會發生呼吸及急促，需要躺下來舒緩症狀", "老人病人通常有疲勞、思緒混亂、食慾不振等症狀，少有乾咳"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:49+00:00", "source_pdf_sha1": "7aa83b1fecb3", "answer_pdf_sha1": "65efadb3135a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "102", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00230', 'dietitian', 'dietitian-moex-114-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關評估重症病人蛋白質需求量時，下列敘述何者錯誤？', '["考量病人的疾病型態、營養狀態及代謝變化，一般給予1.2～2.0 g/kg bw/day", "腎臟功能受損而需要使用連續性腎臟替代療法（continuous renal replacement therapy, CRRT） 時，須限制蛋白質", "重症病人蛋白質的攝取耐受量可達2.0～2.5 g/kg bw/day，但對併發嚴重肝臟疾病的病人則不建議", "給予處於高度代謝狀態時期的重症病人，補充高於一般建議量之蛋白質無法使其達到正氮平衡"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:49+00:00", "source_pdf_sha1": "7aa83b1fecb3", "answer_pdf_sha1": "65efadb3135a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "102", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00231', 'dietitian', 'dietitian-moex-114-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '關於燒燙傷病人體內電解質濃度變化及如何維持其平衡，下列敘述何者錯誤？', '["接受輸液復甦（fluid resuscitation）治療時，靜脈輸入葡萄糖液及大量制酸劑容易引發低磷血 症（hypophosphatemia）", "鎂會在受傷傷口處流失，其補充方式為最好使用靜脈給予，以避免腸道的不適", "鋅是參與能量代謝及蛋白質合成的輔因子，因此燒燙傷病人常會給予220 mg的硫酸鋅（zinc sulfate）補充", "燒燙傷發生初期所產生的貧血與鐵缺乏相關，可補充鐵劑以防止缺乏"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:49+00:00", "source_pdf_sha1": "7aa83b1fecb3", "answer_pdf_sha1": "65efadb3135a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "102", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00232', 'dietitian', 'dietitian-moex-114-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '依據2016年Society of Critical Care Medicine（SCCM）及American Society for Parenteral and Enteral Nutrition（ASPEN）對肥胖重症病人其熱量及蛋白質給予建議，下列何者正確？', '["在給予不分肥胖等級的重症病人腸道營養支持時，熱量給予目標以不超過間接能量分析儀 （indirect calorimetry）所測得熱量之50％為主", "在沒有間接能量分析儀（indirect calorimetry）可使用時，BMI介於30～50的重症病人，其熱量 需求可以用11～14 kcal/kg的理想體重計算", "在沒有間接能量分析儀（indirect calorimetry）可使用時，BMI大於50的肥胖重症病人，其熱量 需求可以用22～25 kcal/kg的理想體重計算", "當病人的BMI為30～40時，蛋白質需要量可以用1.2～1.5 g/kg的理想體重計算"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:49+00:00", "source_pdf_sha1": "7aa83b1fecb3", "answer_pdf_sha1": "65efadb3135a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "102", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
